VALUES
  ('optician-moex-00309', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '大部分軟式水膠隱形眼鏡，含水量為75%時折射率約為1.37～1.38時，若當含水量為20%時，折射率約為多少？', '["1.61～1.63", "1.46～1.48", "1.32～1.33", "1.29～1.30"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00310', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一含水量45%矽水膠材質隱形眼鏡，依照FDA分類為第幾類？', '["二", "三", "四", "五"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00311', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡直徑大小（根據Downie&Lindsay,2015定義）之敘述，下列何者錯誤？', '["一般軟式隱形眼鏡的直徑範圍多為13.0～15.0mm", "硬式隱形眼鏡角膜鏡（corneallens）直徑範圍為7.0～12.0mm", "硬式隱形眼鏡角膜鞏膜鏡（corneo-sclerallens）直徑範圍為15.1～18.0mm", "硬式隱形眼鏡鞏膜鏡（sclerallens）直徑範圍為>18.0mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00312', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '依據鏡片材質特性與研究調查發現，因配戴而導致微生物性角膜炎發生率最低的隱形眼鏡，是下列何者？', '["雙週拋軟式水膠隱形眼鏡", "日戴型軟式矽水膠隱形眼鏡", "持續配戴型軟式矽水膠隱形眼鏡", "硬式透氣隱形眼鏡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00313', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡材質特性的敘述，下列何者錯誤？', '["N-乙烯基吡咯烷酮（N-vinylpyrrolidone,NVP）通常會使鏡片具有離子性", "乙二醇二甲基丙烯酸酯（ethyleneglycoldimethacrylate,EGDMA）會使材質的可拉伸性提高", "甲基丙烯酸甘油酯（glycerylmethacrylate,GMA）具有良好的潤濕性且抗沉積能力高", "甲基丙烯酸羥乙酯（2-hydroxyethylmethacrylate,HEMA）是用於製造第一種商業水膠隱形眼鏡的單體"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00314', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '將下列四種鏡片護理藥水成分，其分子由大而小排列：①Polyquad  ②Hydrogen peroxide  ③Thiomersal', '["Polyhexanide", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00315', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種護理藥水中之防腐劑，其含有去除脂質功能？', '["氯化苯甲烴胺（BenzalkoniumChloride）", "苯甲醇（BenzylAlcohol）", "乙二胺四乙酸鹽（Ethylenediamine）", "氯己定（Chlorhexidine）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00316', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡的物理性消毒清潔有多種方法，依照 FDA 分類方法，何種類型的隱形眼鏡片相對較適合使用加 熱消毒方法？', '["第一類", "第二類", "第三類", "第四類"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00317', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡鏡片清潔的相關敘述，下列何者錯誤？', '["對於隱形眼鏡的配戴者而言，若不進行規律的消毒，會增加眼部感染的風險", "隱形眼鏡保存盒使用方式不當和缺乏洗手，也會增加隱形眼鏡配戴而導致眼部感染的風險", "污染物可能會黏附在鏡片的前後表面導致鏡片扭曲、造成配戴者不舒適及嚴重可能會導致視力減退", "隱形眼鏡配戴者的相關感染風險為非鏡片配戴者的6倍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00318', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '界面活性劑（surfactant）是隱形眼鏡保養液中常含有的一個成分，其最主要的作用為何？', '["清潔鏡片（cleaning）", "消毒殺菌（disinfection）", "濕潤鏡片（wettingagent）", "螯合劑（chelatingagent）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
